#include <fstream>
#include <iostream>
using namespace std;

int main() {
 ifstream file("data.txt");

 // Check if file opened successfully
 if (!file.is_open()) {
 cout << "Error: Could not open file" << endl;
 return 1;
 }

 string line;
 while (getline(file, line)) {
 cout << line << endl;
 }

 // Check why loop ended
 if (file.eof()) {
 cout << "End of file reached" << endl;
 } else if (file.fail()) {
 cout << "Read error occurred" << endl;
 }

 file.close();
 return 0;
}

#include <sstream>
#include <iostream>
#include <string>
using namespace std;

int main() {
 // Number to String
 int num = 42;
 double pi = 3.14159;
 stringstream ss;
 ss << num << " " << pi;
 string str = ss.str();
 cout << "As string: " << str << endl;

 // String to Number
 string input = "100 2.5";
 stringstream ss2(input);
 int a; double b;
 ss2 >> a >> b;
 cout << "Parsed: " << a << " and " << b << endl;

 // Tokenizing
 string data = "apple,banana,cherry";
 stringstream ss3(data);
 string token;
 while (getline(ss3, token, ',')) {
 cout << token << endl;
 }

 return 0;
}

#include <fstream>
#include <iostream>
using namespace std;

struct Student {
 int rollno;
 char name[20];
 float marks;
};

int main() {
 // Write records
 ofstream outFile("students.dat", ios::binary);
 Student s1 = {1, "Alice", 95.5};
 Student s2 = {2, "Bob", 87.0};
 outFile.write((char*)&s1, sizeof(Student));
 outFile.write((char*)&s2, sizeof(Student));
 outFile.close();

 // Read specific record (2nd record)
 ifstream inFile("students.dat", ios::binary);
 inFile.seekg(sizeof(Student), ios::beg); // Skip 1st record
 Student s;
 inFile.read((char*)&s, sizeof(Student));
 cout << "Second student: " << s.name << endl;

 // Get current position
 streampos pos = inFile.tellg();
 cout << "Current position: " << pos << endl;

 inFile.close();
 return 0;
}

#include <iostream>
#include <iomanip>
using namespace std;

int main() {
 // Width and alignment
 cout << left << setw(10) << "Hello" << "|" << endl;
 cout << right << setw(10) << "World" << "|" << endl;

 // Fill character
 cout << setfill('*') << setw(10) << "Test" << endl;

 // Precision
 double pi = 3.14159265;
 cout << "Default: " << pi << endl;
 cout << "Fixed: " << fixed << setprecision(2) << pi << endl;
 cout << "Scientific: " << scientific << pi << endl;

 // Number base
 int num = 255;
 cout << "Decimal: " << dec << num << endl;
 cout << "Hex: " << hex << num << endl;
 cout << "Octal: " << oct << num << endl;

 // Boolean alpha
 cout << boolalpha << true << " " << false << endl;

 return 0;
}
